3	
4	describe("Scenario Runner", () => {
5	  // 1. Single quote step → one {premium}, using yearsWithMHPCO and isFollowUp=false
6	  it("should return one premium result for a single quote step using yearsWithMHPCO and isFollowUp=false", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 5 },
9	      steps: [
10	        {
11	          op: "quote",
12	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
13	        },
14	      ],
15	    });
16	    expect(result).toEqual({ results: [{ premium: 59 }] });
17	  });
18	
19	  // 2. Multiple quotes: first isFollowUp=false, every subsequent isFollowUp=true
20	  it("should treat the first quote as not a follow-up and every subsequent quote as a follow-up", () => {
21	    const result = runScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [
24	        { op: "quote", items: [{ type: "sword" }] },
25	        { op: "quote", items: [{ type: "sword" }] },
26	      ],
27	    });
28	    expect(result.results[0].premium).toBe(115);
29	    expect(result.results[1].premium).toBe(100);
30	  });
31	
32	  // 3. Claim references a quote step by zero-based policy index; result is {payout, remainingCap}
33	  it("should resolve a claim's policy from the referenced quote step and return payout and remainingCap", () => {
34	    const result = runScenario({
35	      customer: { yearsWithMHPCO: 0 },
36	      steps: [
37	        { op: "quote", items: [{ type: "sword", enchantment: 3 }] },
38	        {
39	          op: "claim",
40	          policy: 0,
41	          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 500 }] },
42	        },
43	      ],
44	    });
45	    expect(result.results[0].premium).toBe(115);
46	    expect(result.results[1].payout).toBe(400);
47	    expect(result.results[1].remainingCap).toBe(1600);
48	  });
49	
50	  // 4. Successive claims on the same policy share the cap
51	  it("should start a second claim on the same policy from the remainingCap left by the first claim", () => {
52	    const result = runScenario({
53	      customer: { yearsWithMHPCO: 0 },
54	      steps: [
55	        { op: "quote", items: [{ type: "sword", enchantment: 3 }] },
56	        {
57	          op: "claim",
58	          policy: 0,
59	          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] },
60	        },
61	        {
62	          op: "claim",
63	          policy: 0,
64	          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] },
65	        },
66	      ],
67	    });
68	    expect(result.results[1].payout).toBe(1400);
69	    expect(result.results[1].remainingCap).toBe(600);
70	    expect(result.results[2].payout).toBe(600);
71	    expect(result.results[2].remainingCap).toBe(0);
72	  });
73	
74	  // 5. Results preserve order and length of steps (interleaved quote/claim)
75	  it("should return results in the same order and length as the steps", () => {
76	    const result = runScenario({
77	      customer: { yearsWithMHPCO: 0 },
78	      steps: [
79	        { op: "quote", items: [{ type: "sword", enchantment: 3 }] },
80	        {
