1	import { quote, claim, type Item, type Incident } from "./claim-office.js";
2	
3	export type QuoteStep = {
4	  op: "quote";
5	  items: Item[];
6	};
7	
8	export type ClaimStep = {
9	  op: "claim";
10	  policy: number;
11	  incident: Incident;
12	};
13	
14	export type ScenarioStep = QuoteStep | ClaimStep;
15	
16	export type Scenario = {
17	  customer: { yearsWithMHPCO: number };
18	  steps: ScenarioStep[];
19	};
20	
21	export type StepResult = {
22	  premium?: number;
23	  payout?: number;
24	  remainingCap?: number;
25	};
26	
27	export type ScenarioResult = {
28	  results: StepResult[];
29	};
30	
31	// Tracks how much cap each policy (keyed by its quote step index) has left
32	// after the claims processed so far. Successive claims on the same policy
33	// draw the next claim down from this remaining cap.
34	type RemainingCapByPolicy = Map<number, number>;
35	
36	const isQuoteStep = (step: ScenarioStep): step is QuoteStep => step.op === "quote";
37	
38	const runQuoteStep = (
39	  step: QuoteStep,
40	  priorSteps: ScenarioStep[],
41	  yearsWithMHPCO: number
42	): StepResult => {
43	  const isFollowUp = priorSteps.some(isQuoteStep);
44	  return { premium: quote(step.items, { yearsWithMHPCO, isFollowUp }) };
45	};
46	
47	const runClaimStep = (
48	  step: ClaimStep,
49	  steps: ScenarioStep[],
50	  remainingCapByPolicy: RemainingCapByPolicy
51	): StepResult => {
52	  const policyStep = steps[step.policy];
53	  if (!isQuoteStep(policyStep)) {
54	    throw new Error(`Claim policy index ${step.policy} does not reference a quote step`);
55	  }
56	  const priorCap = remainingCapByPolicy.get(step.policy);
57	  const result =
58	    priorCap === undefined
59	      ? claim(policyStep.items, step.incident)
60	      : claim(policyStep.items, step.incident, priorCap);
61	  remainingCapByPolicy.set(step.policy, result.remainingCap);
62	  return result;
63	};
64	
65	export function runScenario(scenario: Scenario): ScenarioResult {
66	  const { yearsWithMHPCO } = scenario.customer;
67	  const { steps } = scenario;
68	  const remainingCapByPolicy: RemainingCapByPolicy = new Map();
69	  const results = steps.map((step, index): StepResult =>
70	    isQuoteStep(step)
71	      ? runQuoteStep(step, steps.slice(0, index), yearsWithMHPCO)
72	      : runClaimStep(step, steps, remainingCapByPolicy)
73	  );
74	  return { results };
75	}
